export const getGetSyncLogsUrl = (params?: GetSyncLogsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/station/sync-logs?${stringifiedParams}`
    : `/api/station/sync-logs`;
};

export const getSyncLogs = async (
  params?: GetSyncLogsParams,
  options?: RequestInit,
): Promise<SyncLogsResponse> => {
  return customFetch<SyncLogsResponse>(getGetSyncLogsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetSyncLogsQueryKey = (params?: GetSyncLogsParams) => {
  return [`/api/station/sync-logs`, ...(params ? [params] : [])] as const;
};

